func validateCreateTransactionRequest(req *bankingv1.CreateTransactionRequest) error {
	if req.GetFromAccountId() == "" {
		return errors.New("from_account_id is required")
	}
	if req.GetToAccountId() == "" {
		return errors.New("to_account_id is required")
	}
	if req.GetFromAccountId() == req.GetToAccountId() {
		return errors.New("from_account_id and to_account_id must be different")
	}
	if req.GetAmount() <= 0 {
		return errors.New("amount must be greater than zero")
	}
	if req.GetCurrency() == "" {
		return errors.New("currency is required")
	}
	return nil
}

